// Learn: Convert an instant to local formatted time.
import java.time.Instant;
import java.time.Period;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.time.format.DateTimeFormatter;

ZoneId zone = ZoneId.of("Europe/Stockholm");
Instant now = Instant.parse("2026-06-08T10:15:30Z");
ZonedDateTime local = now.atZone(zone);
// DateTimeFormatter controls the output pattern.
DateTimeFormatter formatter = DateTimeFormatter.ofPattern("uuuu-MM-dd HH:mm");
Period reviewWindow = Period.ofMonths(1);
System.out.println(formatter.format(local.plus(reviewWindow)));
